code = """import pandas as pd
import json
# load previous tool results
reviews = pd.DataFrame(var_call_SPySbURuF0WyEWOyi5lnVEeZ)
biz = pd.DataFrame(var_call_p9KqExYKhoPVkjkCcVYIbpo6)
# normalize review counts
reviews['review_count'] = reviews['review_count'].astype(int)
# map business_ref to business_id
reviews['business_id'] = reviews['business_ref'].str.replace('businessref_', 'businessid_')
# merge
df = pd.merge(reviews, biz, on='business_id', how='left')

# function to extract categories from description
import re

def extract_categories(desc):
    if not isinstance(desc, str):
        return []
    low = desc.lower()
    # try several markers
    markers = ['categories of', 'category of', "categories:", "category:", 'in the categories of', 'in the category of']
    start = -1
    mkr = None
    for mk in markers:
        idx = low.find(mk)
        if idx != -1:
            start = idx + len(mk)
            mkr = mk
            break
    if start != -1:
        # extract substring after marker
        sub = desc[start:]
    else:
        # fallback: try to extract stuff after the last 'in the '
        idx = low.rfind('in the ')
        if idx != -1:
            sub = desc[idx+len('in the '):]
        else:
            # fallback: return empty
            return []
    # cleanup
    # remove trailing sentences by cutting at first period
    sub = sub.split('.')[0]
    # remove enclosing quotes or parentheses
    sub = sub.replace("'", "").replace('"', '')
    # split by commas
    parts = [p.strip() for p in re.split(',|;| and | & ', sub) if p.strip()]
    # filter out words like 'this establishment offers' if present
    parts = [p for p in parts if len(p) > 1 and 'offers' not in p.lower() and 'this' not in p.lower()]
    return parts

# expand categories and aggregate
rows = []
for _, r in df.iterrows():
    cats = extract_categories(r.get('description', ''))
    if not cats:
        # try use name as category if nothing found
        continue
    for c in cats:
        rows.append({'category': c, 'review_count': int(r['review_count'])})

if not rows:
    result = []
else:
    rdf = pd.DataFrame(rows)
    agg = rdf.groupby('category', dropna=False)['review_count'].sum().reset_index()
    agg = agg.sort_values('review_count', ascending=False).head(5)
    result = agg.to_dict(orient='records')

print("__RESULT__:")
print(json.dumps(result))"""

